import type { SQL, SQLWrapper } from "../sql.ts";
import { sql, StringChunk } from "../sql.ts";

export type WindowFrameBoundary =
  | typeof unboundedPreceding
  | typeof currentRow
  | typeof unboundedFollowing
  | SQL;

export interface WindowFrame {
  readonly sql: SQL;
}

export interface WindowSpec {
  partitionBy?: SQLWrapper | SQLWrapper[];
  orderBy?: SQLWrapper | SQLWrapper[];
  frame?: WindowFrame;
}

export function buildWindowSpec(spec: WindowSpec): SQL {
  const partitionBy =
    spec.partitionBy === undefined
      ? []
      : Array.isArray(spec.partitionBy)
        ? spec.partitionBy
        : [spec.partitionBy];
  const orderBy =
    spec.orderBy === undefined
      ? []
      : Array.isArray(spec.orderBy)
        ? spec.orderBy
        : [spec.orderBy];
  const partitionSql = partitionBy.length
    ? sql`partition by ${sql.join(partitionBy, sql`, `)} `
    : undefined;
  const orderSql = orderBy.length
    ? sql`order by ${sql.join(orderBy, sql`, `)} `
    : undefined;
  return sql`${partitionSql}${orderSql}${spec.frame?.sql}`;
}

const boundary = (value: string): SQL => sql.raw(value);
export const unboundedPreceding = boundary("unbounded preceding");
export const currentRow = boundary("current row");
export const unboundedFollowing = boundary("unbounded following");

function offsetBoundary(name: "preceding" | "following", value: number): SQL {
  if (!Number.isInteger(value) || value < 0) {
    throw new Error(
      `${name}() requires a non-negative integer; received ${value}`,
    );
  }
  return sql.raw(`${value} ${name}`);
}

export function preceding(value: number): SQL {
  return offsetBoundary("preceding", value);
}
export function following(value: number): SQL {
  return offsetBoundary("following", value);
}

const boundaryOrder = (value: WindowFrameBoundary): number => {
  if (value === unboundedPreceding) return -Infinity;
  if (value === currentRow) return 0;
  if (value === unboundedFollowing) return Infinity;
  const text = value.queryChunks
    .map((chunk) => (is(chunk, StringChunk) ? chunk.value.join("") : ""))
    .join("");
  if (text.endsWith(" preceding")) return -Number(text.slice(0, -10));
  if (text.endsWith(" following")) return Number(text.slice(0, -10));
  return 0;
};

function frame(
  kind: "rows" | "range",
  { from, to }: { from: WindowFrameBoundary; to: WindowFrameBoundary },
): WindowFrame {
  if (boundaryOrder(from) > boundaryOrder(to)) {
    throw new Error(
      'Window frame "from" boundary must not be ordered after "to"',
    );
  }
  return { sql: sql`${sql.raw(kind)} between ${from} and ${to}` };
}

export function rows(spec: {
  from: WindowFrameBoundary;
  to: WindowFrameBoundary;
}): WindowFrame {
  return frame("rows", spec);
}
export function range(spec: {
  from: WindowFrameBoundary;
  to: WindowFrameBoundary;
}): WindowFrame {
  return frame("range", spec);
}

export class WindowFunction<T> implements SQLWrapper {
